from typing import List, Optional, Deque
from collections import deque

class UnionFind:
    """
    A Disjoint Set Union (DSU) data structure for efficiently managing partitions of a set
    into a number of disjoint subsets. It supports two primary operations: finding
    the representative of a set (which can be used to check if two elements are
    in the same set) and uniting two sets.

    Optimized with path compression and union by rank.

    Topics: Union-Find, Graph Theory, Array, Tree (implicit structure).
    """
    def __init__(self, n: int):
        """
        Initializes the Union-Find structure with `n` elements, each in its own set.

        Args:
            n: The number of elements. Elements are 0-indexed (0 to n-1).
        """
        self.parent: List[int] = list(range(n))
        self.rank: List[int] = [0] * n  # Used for union by rank optimization
        self.num_sets: int = n

    def find(self, i: int) -> int:
        """
        Finds the representative (root) of the set containing element `i`.
        Applies path compression during the lookup for efficiency.

        Args:
            i: The element to find the set representative for.

        Returns:
            The representative (root) of the set containing `i`.
        """
        if self.parent[i] == i:
            return i
        # Path compression: make the current node's parent the root
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i: int, j: int) -> bool:
        """
        Unites the sets containing elements `i` and `j`.
        Uses union by rank to keep the tree flatter for efficiency.

        Args:
            i: The first element.
            j: The second element.

        Returns:
            True if the sets were different and were successfully united, False otherwise.
        """
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            # Union by rank: attach smaller rank tree under root of higher rank tree
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_j] < self.rank[root_i]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1
            self.num_sets -= 1
            return True
        return False

    def get_num_sets(self) -> int:
        """
        Returns the current number of disjoint sets.
        """
        return self.num_sets

