class TreeNode:
    """
    Definition for a binary tree node.
    Topics: Tree, Binary Tree, Binary Search Tree (can be used as base), Array (for list representation).
    """
    def __init__(self, val: int = 0, left: Optional['TreeNode'] = None, right: Optional['TreeNode'] = None):
        self.val = val
        self.left = left
        self.right = right

    def __repr__(self) -> str:
        # A simple representation for debugging purposes
        return f"TreeNode(val={self.val})"


def build_binary_tree_from_list(nodes: List[Optional[int]]) -> Optional[TreeNode]:
    """
    Builds a binary tree from a level-order list representation (e.g., LeetCode style).
    `None` values in the list indicate missing child nodes.

    Args:
        nodes: A list of integers or None, representing the tree in level order.
               For example, [3, 9, 20, None, None, 15, 7] represents:
                       3
                      / \
                     9  20
                       /  \
                      15   7

    Returns:
        The root TreeNode of the constructed binary tree, or None if the input list is empty
        or only contains None.

    Topics: Binary Tree, Tree, Array, Breadth-First Search (for construction).
    """
    if not nodes or nodes[0] is None:
        return None

    root_val = nodes[0]
    root = TreeNode(root_val)
    queue: Deque[TreeNode] = deque([root])
    i = 1

    while queue and i < len(nodes):
        current_node = queue.popleft()

        # Build left child
        if i < len(nodes) and nodes[i] is not None:
            left_child = TreeNode(nodes[i])
            current_node.left = left_child
            queue.append(left_child)
        i += 1

        # Build right child
        if i < len(nodes) and i < len(nodes) and nodes[i] is not None:
            right_child = TreeNode(nodes[i])
            current_node.right = right_child
            queue.append(right_child)
        i += 1
    return root

